INSERT INTO projects (title, slug, summary, description, content, cover_image, cover_alt, tech, role, year, featured, client, duration, links, images) VALUES
('Seminar Nasional Pendidikan 2026', 'seminar-nasional-pendidikan-2026', 'Penyediaan 500 paket seminar kit standar untuk peserta dari seluruh Indonesia.', 'Kami bangga menjadi mitra pengadaan seminar kit untuk Seminar Nasional Pendidikan 2026 yang dihadiri oleh guru dan praktisi pendidikan dari seluruh Nusantara.', 'Acara ini membutuhkan pengiriman yang cepat dan presisi. Kami menyediakan 500 tote bag sablon, blocknote, pulpen, dan sertifikat cetak yang diselesaikan dalam waktu 1 minggu.', '/uploads/1783517552510-lh7t5e-portofolio.png', 'Suasana Seminar Nasional', '["Tote Bag", "Blocknote", "Sertifikat"]', 'Vendor Merchandise', '2026', true, 'Universitas Indonesia', '1 Minggu', '{}', '[]'),
('Konferensi Teknologi & Inovasi (TechCon)', 'techcon-2026', 'Distribusi 1000 paket premium VIP untuk startup founder dan investor.', 'TechCon membutuhkan perlengkapan yang merepresentasikan inovasi dan kemewahan. Kami mensuplai ransel laptop dan tumbler pintar.', 'Peserta sangat menyukai tumbler pintar dengan pengukur suhu yang kami berikan. Logo TechCon digrafir elegan pada setiap tumbler.', '/uploads/1783351769512-smf6gf-seminar1.png', 'TechCon 2026 VIP Kit', '["Ransel Laptop", "Smart Tumbler", "Flashdisk Custom"]', 'Vendor Utama', '2026', true, 'TechCorp Indonesia', '3 Minggu', '{}', '[]'),
('Workshop Digital Marketing', 'workshop-digital-marketing', 'Pengadaan 200 paket alat tulis dan ID card eksklusif.', 'Untuk workshop intensif selama 2 hari, peserta membutuhkan alat tulis yang nyaman dan ID Card yang kokoh.', 'Kami mendesain khusus Lanyard dengan warna brand klien dan blocknote ring yang mudah digunakan selama sesi praktek digital marketing.', '/uploads/1783517693698-b7aiqk-mockup_souvenir_premium_kantor.webp', 'Alat tulis workshop', '["Lanyard Custom", "Blocknote Ring", "Pulpen Stylus"]', 'Vendor Sablon & Cetak', '2025', false, 'Marketer ID', '5 Hari', '{}', '[]'),
('Rapat Kerja Nasional Kementerian X', 'rakernas-kementerian', 'Paket seminar formal (tas dokumen dan agenda kulit) untuk 300 pejabat.', 'Rakernas membutuhkan tampilan yang sangat formal dan rapi. Kami menyediakan map dokumen kulit sintetis dan pulpen besi.', 'Kualitas jahitan map dokumen menjadi fokus utama kami untuk memastikan kesan elegan dan tahan lama bagi para peserta.', '/uploads/1783686048996-zhdpwr-komposisi-meja-kerja-minimalis-elegan.webp', 'Meja kerja rapi', '["Agenda Kulit", "Map Dokumen", "Pulpen Besi"]', 'Vendor Pengadaan', '2025', false, 'Kementerian X', '2 Minggu', '{}', '[]'),
('Pelatihan Kepemimpinan Mahasiswa BEM', 'pelatihan-bem', 'Paket outbound dan seminar (kaos dan pouch) untuk 150 mahasiswa.', 'Selain sesi ruangan, acara ini memiliki sesi outbound. Kami menyediakan pouch tahan air dan kaos kegiatan yang menyerap keringat.', 'Pouch custom yang kami buat ternyata sangat berguna bagi mahasiswa untuk menyimpan smartphone mereka selama sesi lapangan.', '/uploads/1783268346469-e1ye8v-outbound-katun-coban-talun-batu.png', 'Pouch kegiatan lapangan', '["Kaos Kegiatan", "Pouch Anti Air", "Topi Sablon"]', 'Konveksi & Merchandise', '2025', false, 'BEM Universitas Y', '2 Minggu', '{}', '[]');

