INSERT INTO blog_posts (title, slug, excerpt, content, cover_image, read_time, is_featured, tags) VALUES
('Panduan Lengkap Memilih Paket SeminarKit', 'panduan-memilih-seminarkit', 'Jangan salah pilih! Ketahui cara menyesuaikan paket dengan budget.', 'Memilih perlengkapan seminar seringkali membingungkan. Pertama, pastikan siapa target audiens Anda. Jika mahasiswa, paket basic sudah cukup...', '/uploads/1783178103412-gd80xb-artikelblog.webp', 5, true, '["Panduan", "Tips", "Budgeting"]'),
('Mengapa Souvenir Ramah Lingkungan Diminati?', 'souvenir-ramah-lingkungan', 'Tren eco-friendly kini merambah ke dunia merchandise acara.', 'Menggunakan tote bag dari bahan daur ulang tidak hanya menyelamatkan bumi, tetapi juga meningkatkan citra positif perusahaan Anda...', '/uploads/1783517812554-xw6aas-artikel-atas.webp', 4, true, '["Eco-Friendly", "Tren", "Green Event"]'),
('Tips Menghemat Budget Merchandise', 'tips-menghemat-budget-merchandise', 'Anda punya budget terbatas? Ini rahasia agar kit Anda tetap elegan.', 'Fokuslah pada desain, bukan sekadar harga barang. Sebuah tote bag blacu murah akan terlihat sangat premium jika desain sablonnya minimalis...', '/uploads/1783322932782-6j9hsz-artikelblog__1_.webp', 3, false, '["Budget", "Desain", "Tips"]'),
('Pentingnya Name Tag Profesional dalam Acara', 'pentingnya-name-tag-profesional', 'Name tag bukan sekadar tanda pengenal, tapi juga alat networking.', 'ID card yang desainnya jelas dan tulisannya besar akan sangat memudahkan peserta untuk saling bertegur sapa dan melakukan networking...', '/uploads/1783351569517-u87c5a-strategi-atas.webp', 4, false, '["Networking", "Lanyard", "Event Management"]'),
('Tren Souvenir Seminar & Konferensi 2026', 'tren-souvenir-seminar-2026', 'Tinggalkan blocknote biasa! Ini inovasi merchandise tahun ini.', 'Smart tumbler yang menampilkan suhu air dan UV sterilizer box mini kini mulai menggantikan jam dinding sebagai souvenir favorit korporat...', '/uploads/1783348689750-uqxre6-9.webp', 6, false, '["Tren 2026", "Teknologi", "Inovasi"]');
